import jwt
import json
from datetime import datetime
from typing import Dict, Any, Optional, Tuple


def decode_jwt(token: str, secret: Optional[str] = None, verify: bool = False, 
               algorithms: list = None) -> Tuple[Dict[str, Any], Dict[str, Any]]:
    """
    Decode and optionally verify a JWT token for debugging purposes.
    
    Args:
        token: The JWT token string
        secret: Secret key for verification (optional)
        verify: Whether to verify the signature
        algorithms: List of allowed algorithms (default: ['HS256', 'HS512', 'RS256'])
    
    Returns:
        Tuple of (decoded_payload, token_info)
    """
    if algorithms is None:
        algorithms = ['HS256', 'HS512', 'RS256', 'RS512', 'ES256', 'ES512']
    
    token_info = {
        'valid': False,
        'expired': False,
        'error': None,
        'header': {},
        'payload': {},
        'signature_verified': False
    }
    
    try:
        # Decode header without verification
        token_info['header'] = jwt.get_unverified_header(token)
        
        if verify and secret:
            # Decode and verify
            decoded = jwt.decode(token, secret, algorithms=algorithms)
            token_info['signature_verified'] = True
            token_info['valid'] = True
        else:
            # Decode without verification
            decoded = jwt.decode(token, options={"verify_signature": False}, algorithms=algorithms)
            token_info['valid'] = True
        
        token_info['payload'] = decoded
        
        # Check expiration
        if 'exp' in decoded:
            exp_timestamp = decoded['exp']
            exp_datetime = datetime.fromtimestamp(exp_timestamp)
            token_info['expiration'] = exp_datetime.isoformat()
            token_info['expired'] = datetime.now() > exp_datetime
        
        # Check issued at
        if 'iat' in decoded:
            iat_timestamp = decoded['iat']
            iat_datetime = datetime.fromtimestamp(iat_timestamp)
            token_info['issued_at'] = iat_datetime.isoformat()
        
        # Check not before
        if 'nbf' in decoded:
            nbf_timestamp = decoded['nbf']
            nbf_datetime = datetime.fromtimestamp(nbf_timestamp)
            token_info['not_before'] = nbf_datetime.isoformat()
        
        return decoded, token_info
        
    except jwt.ExpiredSignatureError as e:
        token_info['error'] = 'Token has expired'
        token_info['expired'] = True
        # Still decode to see contents
        try:
            decoded = jwt.decode(token, options={"verify_signature": False}, algorithms=algorithms)
            token_info['payload'] = decoded
            return decoded, token_info
        except:
            return {}, token_info
            
    except jwt.InvalidSignatureError as e:
        token_info['error'] = 'Invalid signature'
        try:
            decoded = jwt.decode(token, options={"verify_signature": False}, algorithms=algorithms)
            token_info['payload'] = decoded
            return decoded, token_info
        except:
            return {}, token_info
            
    except jwt.DecodeError as e:
        token_info['error'] = f'Decode error: {str(e)}'
        return {}, token_info
        
    except Exception as e:
        token_info['error'] = f'Unexpected error: {str(e)}'
        return {}, token_info


def print_jwt_info(token: str, secret: Optional[str] = None, verify: bool = False):
    """
    Print formatted JWT token information for debugging.
    """
    print("=" * 80)
    print("JWT TOKEN ANALYSIS")
    print("=" * 80)
    
    decoded, info = decode_jwt(token, secret, verify)
    
    print("\n[HEADER]")
    print(json.dumps(info['header'], indent=2))
    
    print("\n[PAYLOAD]")
    print(json.dumps(info['payload'], indent=2))
    
    print("\n[STATUS]")
    print(f"Valid: {info['valid']}")
    print(f"Signature Verified: {info['signature_verified']}")
    print(f"Expired: {info['expired']}")
    
    if 'expiration' in info:
        print(f"Expiration: {info['expiration']}")
    if 'issued_at' in info:
        print(f"Issued At: {info['issued_at']}")
    if 'not_before' in info:
        print(f"Not Before: {info['not_before']}")
    
    if info['error']:
        print(f"\n[ERROR]")
        print(f"{info['error']}")
    
    print("\n" + "=" * 80)


